class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        from collections import Counter
        cnt=Counter(nums); ends=Counter()
        for x in nums:
            if cnt[x]==0: continue
            cnt[x]-=1
            if ends[x-1]:
                ends[x-1]-=1; ends[x]+=1
            elif cnt[x+1]:
                cnt[x+1]-=1; ends[x+1]+=1
            else: return False
        return True

