class Solution {
public:
    bool isPossible(vector<int>& nums) {
        unordered_map<int,int> cnt, end;
        for(int x:nums) cnt[x]++;
        for(int x:nums){
            if(!cnt[x]) continue; cnt[x]--;
            if(end[x-1]){ end[x-1]--; end[x]++; }
            else if(cnt[x+1]){ cnt[x+1]--; end[x+1]++; }
            else return false;
        }
        return true;
    }
};
